                                            text = if (isNepal) "Target District in Nepal (जिल्ला)" else "Target City (नगर)",
                                            fontSize = 11.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = MaterialTheme.colorScheme.primary
                                        )
                                        
                                        Box(modifier = Modifier.fillMaxWidth()) {
