                    5 -> { // CV STRUCTURE ORDER & SECTION REORDERING & CUSTOM SECTIONS CONTROL
                        val customDataMap by viewModel.customSectionDataState.collectAsStateWithLifecycle()
                        FormSectionHeader("CV STRUCTURE CONTROL")
                        Text(
                            "Arrange order, toggle visibility, rename headings, and insert custom paragraph/text blocks freely. Order numbers are updated instantly in the live design below.",
                            fontSize = 11.sp,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Spacer(modifier = Modifier.height(10.dp))

                        // Reorderable Action Buttons list
                        var draggingIndex by remember { mutableStateOf<Int?>(null) }
                        var dragOffsetY by remember { mutableStateOf(0f) }

                        val sortedSections = custom.sections.sortedBy { it.order }
                        sortedSections.forEachIndexed { index, sec ->
                            val isDraggingThis = draggingIndex == index
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .zIndex(if (isDraggingThis) 10f else 0f)
                                    .graphicsLayer {
                                        translationY = if (isDraggingThis) dragOffsetY else 0f
                                        val scale = if (isDraggingThis) 1.03f else 1.0f
                                        scaleX = scale
                                        scaleY = scale
                                    },
                                colors = CardDefaults.cardColors(
                                    containerColor = if (isDraggingThis) {
                                        MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.85f)
                                    } else if (sec.isHidden) {
                                        Color.LightGray.copy(alpha = 0.2f)
                                    } else {
                                        MaterialTheme.colorScheme.primary.copy(alpha = 0.05f)
                                    }
                                ),
                                border = androidx.compose.foundation.BorderStroke(
                                    width = if (isDraggingThis) 2.dp else 1.dp,
                                    color = if (isDraggingThis) {
                                        MaterialTheme.colorScheme.primary
                                    } else if (sec.isHidden) {
                                        Color.LightGray
                                    } else {
                                        MaterialTheme.colorScheme.primary.copy(alpha = 0.3f)
                                    }
                                ),
                                elevation = CardDefaults.cardElevation(
                                    defaultElevation = if (isDraggingThis) 10.dp else 2.dp
                                )
                            ) {
                                Column(modifier = Modifier.padding(10.dp)) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                                    ) {
                                        // Tactical Drag handle
                                        Icon(
                                            imageVector = Icons.Default.DragHandle,
                                            contentDescription = "Drag to reorder",
                                            tint = if (isDraggingThis) MaterialTheme.colorScheme.primary else Color.Gray,
                                            modifier = Modifier
                                                .size(28.dp)
                                                .pointerInput(index) {
                                                    detectDragGestures(
                                                        onDragStart = { _ ->
                                                            draggingIndex = index
                                                            dragOffsetY = 0f
                                                        },
                                                        onDrag = { change, dragAmount ->
                                                            change.consume()
                                                            dragOffsetY += dragAmount.y
                                                            
                                                            val threshold = 180f
                                                            val from = draggingIndex
                                                            if (from != null) {
                                                                if (dragOffsetY > threshold && from < sortedSections.size - 1) {
                                                                    viewModel.moveSection(from, from + 1)
                                                                    draggingIndex = from + 1
                                                                    dragOffsetY = 0f
                                                                } else if (dragOffsetY < -threshold && from > 0) {
                                                                    viewModel.moveSection(from, from - 1)
                                                                    draggingIndex = from - 1
                                                                    dragOffsetY = 0f
                                                                }
                                                            }
                                                        },
                                                        onDragEnd = {
                                                            draggingIndex = null
                                                            dragOffsetY = 0f
                                                        },
                                                        onDragCancel = {
                                                            draggingIndex = null
                                                            dragOffsetY = 0f
                                                        }
                                                    )
                                                }
                                        )

                                        Icon(
                                            imageVector = when (sec.id) {
                                                "personal" -> Icons.Default.Person
